    # Add new node with name new_EK_PORT_21, type EK_PORT, and default physical capacity
    new_node_name = 'new_EK_PORT_21'
    graph_copy.add_node(new_node_name, name=new_node_name, type=['EK_PORT'], physical_capacity_bps=1000)

    # Add edge from ju1.s4.s2c4 to the new node with RK_CONTAINS type
    parent_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'] == 'ju1.s4.s2c4':
            parent_node = node[0]
            break
    if parent_node:
        graph_copy.add_edge(parent_node, new_node_name, type='RK_CONTAINS')

    # Count the number of EK_PORT nodes contained in the same hierarchy under ju1.s4.s2c4
    port_count = 0
    for node in graph_copy.nodes(data=True):
        # Check if it's a PORT and its name starts with 'ju1.s4.s2c4'
        if 'EK_PORT' in node[1]['type'] and node[1]['name'].startswith('ju1.s4.s2c4'):
            port_count += 1

    # Prepare return object
    return_object = {
        'type': 'text',
        'data': str(port_count),
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return return_object

